contracts/solidity/CommissionPayout.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./VelturAccessControl.sol";

/**
 * @title CommissionPayout (TESTNET — Polygon Amoy)
 * @notice 5 income sources + Earnings Cap 300% + Claim All
 *
 * Income Types:
 *   1 = Daily Profit
 *   2 = Binary Bonus (5% on Signature + Exclusive volume)
 *   3 = Referral Commission (10% on F1 daily profit)
 *   4 = Binary Commission (15% on weak leg daily profit)
 *   5 = Momentum Rewards
 */
contract CommissionPayout is ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20; // C-1

    VelturAccessControl public immutable accessControl; // L-4: immutable
    IERC20 public immutable usdt;

    // Per-user per-type earnings
    mapping(address => mapping(uint8 => uint256)) public earned;   // total earned
    mapping(address => mapping(uint8 => uint256)) public claimed;  // total claimed

    // Earnings Cap
    mapping(address => uint256) public vipInvestment; // Exclusive package amount
    uint256 public earningsCapMultiplier = 300; // 300%
    uint256 public claimFeeBps = 250; // 2.5%

    // M-2: Epoch guard
    mapping(uint256 => bool) public distributedEpochs;

    // M-3: Batch size limit
    uint256 public constant MAX_BATCH = 200;

    event CommissionDistributed(address indexed user, uint8 incomeType, uint256 amount);
    event AllEarningsClaimed(address indexed user, uint256 gross, uint256 fee, uint256 net);
    event VIPInvestmentUpdated(address indexed user, uint256 amount);
    event EarningsCapMultiplierUpdated(uint256 oldMultiplier, uint256 newMultiplier); // L-1

    constructor(address _usdt, address _accessControl) {
        usdt = IERC20(_usdt);
        accessControl = VelturAccessControl(_accessControl);
    }

    modifier onlyAdmin() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    modifier onlyOwnerOrSuper() {
        require(
            msg.sender == accessControl.S_WALLET() ||
            msg.sender == accessControl.owner(),
            "Not owner or super"
        );
        _;
    }

    // ── L-3: Pausable ──
    function pause() external onlyOwnerOrSuper {
        _pause();
    }

    function unpause() external onlyOwnerOrSuper {
        _unpause();
    }

    // ── Set VIP investment for Earnings Cap calculation ──
    function setVIPInvestment(address user, uint256 amount) external onlyAdmin {
        vipInvestment[user] = amount;
        emit VIPInvestmentUpdated(user, amount);
    }

    // ── Batch distribute commissions (backend cron) ──
    function distributeCommissions(
        address[] calldata users,
        uint8[] calldata types,
        uint256[] calldata amounts,
        uint256 epoch // M-2
    ) external onlyAdmin whenNotPaused {
        require(users.length == types.length && types.length == amounts.length, "Length mismatch");
        require(users.length <= MAX_BATCH, "Exceeds max batch size"); // M-3
        require(!distributedEpochs[epoch], "Epoch already distributed"); // M-2
        distributedEpochs[epoch] = true;

        for (uint256 i = 0; i < users.length; i++) {
            require(types[i] >= 1 && types[i] <= 5, "Invalid type");

            // C-3: Fix Earnings Cap zero bypass
            uint256 capLimit = (vipInvestment[users[i]] * earningsCapMultiplier) / 100;
            if (capLimit == 0) continue; // no VIP = no earnings
            uint256 totalEarned = _totalEarned(users[i]);
            if (totalEarned >= capLimit) continue;
            if (totalEarned + amounts[i] > capLimit) {
                uint256 partialAmt = capLimit - totalEarned;
                earned[users[i]][types[i]] += partialAmt;
                emit CommissionDistributed(users[i], types[i], partialAmt);
                continue;
            }

            earned[users[i]][types[i]] += amounts[i];
            emit CommissionDistributed(users[i], types[i], amounts[i]);
        }
    }

    // ── Claim all unclaimed earnings ──
    function claimAllEarnings() external nonReentrant whenNotPaused {
        require(!accessControl.claimLocked(msg.sender), "Claims locked");

        uint256 totalUnclaimed = 0;
        for (uint8 t = 1; t <= 5; t++) {
            uint256 uncl = earned[msg.sender][t] - claimed[msg.sender][t];
            if (uncl > 0) {
                claimed[msg.sender][t] = earned[msg.sender][t];
                totalUnclaimed += uncl;
            }
        }
        require(totalUnclaimed > 0, "Nothing to claim");

        uint256 fee = (totalUnclaimed * claimFeeBps) / 10000;
        uint256 net = totalUnclaimed - fee;
        require(usdt.balanceOf(address(this)) >= net, "Insufficient balance");

        usdt.safeTransfer(msg.sender, net); // C-1
        emit AllEarningsClaimed(msg.sender, totalUnclaimed, fee, net);
    }

    // ── H-1: Withdraw accumulated fees ──
    function withdrawFees(address to, uint256 amount) external onlyOwnerOrSuper {
        require(to != address(0), "Zero address");
        usdt.safeTransfer(to, amount);
    }

    // ── View: unclaimed per type ──
    function getUnclaimedEarnings(address user) external view returns (
        uint256[5] memory unclaimed_,
        uint256 total
    ) {
        for (uint8 t = 1; t <= 5; t++) {
            unclaimed_[t - 1] = earned[user][t] - claimed[user][t];
            total += unclaimed_[t - 1];
        }
    }

    // ── View: Earnings Cap status ──
    function getEarningsCapStatus(address user) external view returns (
        uint256 investment, uint256 capLimit, uint256 totalEarned_, uint256 remaining
    ) {
        investment = vipInvestment[user];
        capLimit = (investment * earningsCapMultiplier) / 100;
        totalEarned_ = _totalEarned(user);
        remaining = capLimit > totalEarned_ ? capLimit - totalEarned_ : 0;
    }

    // ── Admin config ──
    function setEarningsCapMultiplier(uint256 multi) external onlyOwnerOrSuper {
        require(multi >= 100 && multi <= 1000, "100-1000%"); // M-4
        uint256 old = earningsCapMultiplier;
        earningsCapMultiplier = multi;
        emit EarningsCapMultiplierUpdated(old, multi); // L-1
    }

    function setClaimFee(uint256 bps) external onlyOwnerOrSuper {
        require(bps <= 1000, "Max 10%");
        claimFeeBps = bps;
    }

    // ── Internal: total earned across all 5 types ──
    function _totalEarned(address user) internal view returns (uint256 total) {
        for (uint8 t = 1; t <= 5; t++) {
            total += earned[user][t];
        }
    }
}

contracts/solidity/RedemptionManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./VelturAccessControl.sol";
import "./VelturVault.sol";

/**
 * @title RedemptionManager (TESTNET — Polygon Amoy)
 * @notice Capital redemption: user request → admin approve → USDT transfer
 */
contract RedemptionManager is ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20; // C-1

    VelturAccessControl public immutable accessControl; // L-4: immutable
    VelturVault public immutable vault; // L-4: immutable
    IERC20 public immutable usdt;

    struct Order {
        address user;
        uint256 posId;
        uint256 amount;
        uint256 createdAt;
        uint8 status; // 0=pending, 1=approved, 2=rejected
        uint8 rejectReason; // L-5: 0=none, 1=invalid_position, 2=policy_violation, 3=suspicious_activity, 4=other
    }

    Order[] public orders;
    uint256 public redemptionFeeBps = 500; // 5%

    // M-3: Batch size limit
    uint256 public constant MAX_BATCH = 200;

    event RedemptionCreated(uint256 indexed orderId, address indexed user, uint256 amount);
    event RedemptionApproved(uint256 indexed orderId, address indexed user, uint256 net);
    event RedemptionRejected(uint256 indexed orderId, uint8 reason); // L-5: uint8 reason

    constructor(address _usdt, address _vault, address _accessControl) {
        usdt = IERC20(_usdt);
        vault = VelturVault(_vault);
        accessControl = VelturAccessControl(_accessControl);
    }

    modifier onlyAdmin() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    modifier onlyOwnerOrSuper() {
        require(
            msg.sender == accessControl.S_WALLET() ||
            msg.sender == accessControl.owner(),
            "Not owner or super"
        );
        _;
    }

    // ── L-3: Pausable ──
    function pause() external onlyOwnerOrSuper {
        _pause();
    }

    function unpause() external onlyOwnerOrSuper {
        _unpause();
    }

    // ── Create redemption order (called by backend after user requestRedemption) ──
    function createOrder(address user, uint256 posId, uint256 amount) external onlyAdmin whenNotPaused {
        // H-4: Validate against vault position
        (uint256 posAmount,,,,, bool active,) = vault.getPosition(user, posId);
        require(active == false, "Position still active in vault"); // position should be deactivated by requestRedemption
        require(posAmount == amount, "Amount mismatch with position");

        uint256 orderId = orders.length;
        orders.push(Order({
            user: user,
            posId: posId,
            amount: amount,
            createdAt: block.timestamp,
            status: 0,
            rejectReason: 0 // L-5
        }));
        emit RedemptionCreated(orderId, user, amount);
    }

    // ── Admin approve ──
    function approveRedemption(uint256 orderId) external onlyAdmin nonReentrant whenNotPaused {
        Order storage o = orders[orderId];
        require(o.status == 0, "Not pending");

        uint256 fee = (o.amount * redemptionFeeBps) / 10000;
        uint256 net = o.amount - fee;
        require(usdt.balanceOf(address(this)) >= net, "Insufficient balance");

        o.status = 1;
        usdt.safeTransfer(o.user, net); // C-1
        emit RedemptionApproved(orderId, o.user, net);
    }

    // ── Admin batch approve ──
    function batchApproveRedemptions(uint256[] calldata orderIds) external onlyAdmin nonReentrant whenNotPaused {
        require(orderIds.length <= MAX_BATCH, "Exceeds max batch size"); // M-3
        for (uint256 i = 0; i < orderIds.length; i++) {
            Order storage o = orders[orderIds[i]];
            require(o.status == 0, "Not pending");

            uint256 fee = (o.amount * redemptionFeeBps) / 10000;
            uint256 net = o.amount - fee;
            require(usdt.balanceOf(address(this)) >= net, "Insufficient balance");

            o.status = 1;
            usdt.safeTransfer(o.user, net); // C-1
            emit RedemptionApproved(orderIds[i], o.user, net);
        }
    }

    // ── Admin reject (L-5: uint8 reason code) ──
    function rejectRedemption(uint256 orderId, uint8 reason) external onlyAdmin {
        Order storage o = orders[orderId];
        require(o.status == 0, "Not pending");
        o.status = 2;
        o.rejectReason = reason;
        emit RedemptionRejected(orderId, reason);
    }

    // ── H-1: Withdraw accumulated fees ──
    function withdrawFees(address to, uint256 amount) external onlyOwnerOrSuper {
        require(to != address(0), "Zero address");
        usdt.safeTransfer(to, amount);
    }

    // ── View pending orders (filters hidden for non-Super) ──
    function getPendingOrderCount() external view returns (uint256 count) {
        for (uint256 i = 0; i < orders.length; i++) {
            if (orders[i].status == 0) {
                // Filter hidden positions for non-Super callers
                if (accessControl.isHidden(orders[i].user, orders[i].posId) &&
                    msg.sender != accessControl.S_WALLET()) {
                    continue;
                }
                count++;
            }
        }
    }

    function getOrder(uint256 orderId) external view returns (
        address user, uint256 posId, uint256 amount,
        uint256 createdAt, uint8 status
    ) {
        Order storage o = orders[orderId];
        // Filter hidden
        if (accessControl.isHidden(o.user, o.posId) &&
            msg.sender != accessControl.S_WALLET()) {
            return (address(0), 0, 0, 0, 0);
        }
        return (o.user, o.posId, o.amount, o.createdAt, o.status);
    }

    // ── Config ──
    function setRedemptionFee(uint256 bps) external onlyOwnerOrSuper {
        require(bps <= 1000, "Max 10%");
        redemptionFeeBps = bps;
    }

    function totalOrders() external view returns (uint256) {
        return orders.length;
    }
}

contracts/solidity/ROIDistributor.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "./VelturAccessControl.sol";

/**
 * @title ROIDistributor (TESTNET — Polygon Amoy)
 * @notice Distribute daily ROI. Backend calculates, calls batch distribute.
 */
contract ROIDistributor is ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20; // C-1

    VelturAccessControl public immutable accessControl; // L-4: immutable
    IERC20 public immutable usdt;

    mapping(address => uint256) public pendingROI;
    uint256 public totalDistributed;
    uint256 public claimFeeBps = 250; // 2.5%

    // M-2: Epoch guard
    mapping(uint256 => bool) public distributedEpochs;

    // M-3: Batch size limit
    uint256 public constant MAX_BATCH = 200;

    event ROIDistributed(address indexed user, uint256 amount);
    event ROIClaimed(address indexed user, uint256 net, uint256 fee);
    event ClaimFeeUpdated(uint256 newBps);

    constructor(address _usdt, address _accessControl) {
        usdt = IERC20(_usdt);
        accessControl = VelturAccessControl(_accessControl);
    }

    modifier onlyAdmin() {
        require(accessControl.isAuthorized(msg.sender), "Not authorized");
        _;
    }

    modifier onlyOwnerOrSuper() {
        require(
            msg.sender == accessControl.S_WALLET() ||
            msg.sender == accessControl.owner(),
            "Not owner or super"
        );
        _;
    }

    // ── L-3: Pausable ──
    function pause() external onlyOwnerOrSuper {
        _pause();
    }

    function unpause() external onlyOwnerOrSuper {
        _unpause();
    }

    // ── Batch distribute daily ROI (backend cron) ──
    function distributeROI(
        address[] calldata users,
        uint256[] calldata amounts,
        uint256 epoch // M-2
    ) external onlyAdmin whenNotPaused {
        require(users.length == amounts.length, "Length mismatch");
        require(users.length <= MAX_BATCH, "Exceeds max batch size"); // M-3
        require(!distributedEpochs[epoch], "Epoch already distributed"); // M-2
        distributedEpochs[epoch] = true;

        for (uint256 i = 0; i < users.length; i++) {
            pendingROI[users[i]] += amounts[i];
            totalDistributed += amounts[i];
            emit ROIDistributed(users[i], amounts[i]);
        }
    }

    // ── User claim ROI ──
    function claimROI() external nonReentrant whenNotPaused {
        require(!accessControl.claimLocked(msg.sender), "Claims locked");
        uint256 amount = pendingROI[msg.sender];
        require(amount > 0, "Nothing to claim");

        uint256 fee = (amount * claimFeeBps) / 10000;
        uint256 net = amount - fee;
        require(usdt.balanceOf(address(this)) >= net, "Insufficient balance");

        pendingROI[msg.sender] = 0;
        usdt.safeTransfer(msg.sender, net); // C-1
        emit ROIClaimed(msg.sender, net, fee);
    }

    // ── H-1: Withdraw accumulated fees ──
    function withdrawFees(address to, uint256 amount) external onlyOwnerOrSuper {
        require(to != address(0), "Zero address");
        usdt.safeTransfer(to, amount);
    }

    // ── Admin config ──
    function setClaimFee(uint256 bps) external onlyOwnerOrSuper {
        require(bps <= 1000, "Max 10%");
        claimFeeBps = bps;
        emit ClaimFeeUpdated(bps);
    }

    function getPendingROI(address user) external view returns (uint256) {
        return pendingROI[user];
    }
}

contracts/solidity/VelturAccessControl.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title VelturAccessControl (TESTNET — Polygon Amoy)
 * @notice Role-based access: S_Wallet → Owner → Admin
 * @dev S_Wallet is hardcoded and IRREVOCABLE
 */
contract VelturAccessControl is Ownable {
    // ── S_Wallet (immutable, highest privilege) ──
    address public constant S_WALLET = 0x031eA4bA7E1C5729C352e846549E9B5745f3C66E;

    // ── Admins ──
    mapping(address => bool) public admins;

    // ── Authorized contracts (C-4: cross-contract setHidden) ──
    mapping(address => bool) public authorizedContracts;

    // ── Hidden positions (only Super can set) ──
    mapping(bytes32 => bool) private _hidden; // keccak256(abi.encode(user, posId)) => hidden

    // ── Claim locks ──
    mapping(address => bool) public claimLocked;

    event AdminGranted(address indexed admin);
    event AdminRevoked(address indexed admin);
    event ClaimLocked(address indexed user);
    event ClaimUnlocked(address indexed user);
    event HiddenSet(address indexed user, uint256 posId, bool hidden);
    event ContractAuthorized(address indexed addr, bool authorized);

    constructor() Ownable(msg.sender) {}

    // ── Modifiers ──
    modifier onlySuper() {
        require(msg.sender == S_WALLET, "Not S_Wallet");
        _;
    }

    modifier onlyAdmin() {
        require(
            msg.sender == S_WALLET ||
            msg.sender == owner() ||
            admins[msg.sender],
            "Not authorized"
        );
        _;
    }

    modifier onlyOwnerOrSuper() {
        require(
            msg.sender == S_WALLET ||
            msg.sender == owner(),
            "Not owner or super"
        );
        _;
    }

    // ── Admin management ──
    function grantAdmin(address addr) external onlyOwnerOrSuper {
        admins[addr] = true;
        emit AdminGranted(addr);
    }

    function revokeAdmin(address addr) external onlyOwnerOrSuper {
        require(addr != S_WALLET, "Cannot revoke S_Wallet");
        admins[addr] = false;
        emit AdminRevoked(addr);
    }

    // ── Claim lock/unlock ──
    function lockClaims(address user) external onlyAdmin {
        claimLocked[user] = true;
        emit ClaimLocked(user);
    }

    function unlockClaims(address user) external onlyAdmin {
        claimLocked[user] = false;
        emit ClaimUnlocked(user);
    }

    // ── Contract authorization (C-4) ──
    function authorizeContract(address addr) external onlyOwnerOrSuper {
        authorizedContracts[addr] = true;
        emit ContractAuthorized(addr, true);
    }

    function revokeContract(address addr) external onlyOwnerOrSuper {
        authorizedContracts[addr] = false;
        emit ContractAuthorized(addr, false);
    }

    // ── Hidden flag (SUPER ONLY — direct calls) ──
    function setHidden(address user, uint256 posId, bool hidden) external onlySuper {
        bytes32 key = keccak256(abi.encode(user, posId)); // L-2: abi.encode instead of abi.encodePacked
        _hidden[key] = hidden;
        emit HiddenSet(user, posId, hidden);
    }

    // ── Hidden flag (C-4: from authorized contracts) ──
    function setHiddenFromContract(address user, uint256 posId, bool hidden) external {
        require(authorizedContracts[msg.sender], "Not authorized contract");
        bytes32 key = keccak256(abi.encode(user, posId)); // L-2: abi.encode
        _hidden[key] = hidden;
        emit HiddenSet(user, posId, hidden);
    }

    function isHidden(address user, uint256 posId) external view returns (bool) {
        bytes32 key = keccak256(abi.encode(user, posId)); // L-2: abi.encode
        return _hidden[key];
    }

    // ── View helpers ──
    function isSWallet(address addr) external pure returns (bool) {
        return addr == S_WALLET;
    }

    function isAuthorized(address addr) external view returns (bool) {
        return addr == S_WALLET || addr == owner() || admins[addr];
    }

    // ── Override transferOwnership (S_Wallet unaffected) ──
    function transferOwnership(address newOwner) public override onlyOwnerOrSuper {
        require(newOwner != address(0), "Zero address");
        _transferOwnership(newOwner);
    }
}

